def binary_search_iterative(arr, target):
    low = 0
    high = len(arr) - 1

    while low <= high:
        mid = (low + high) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            low = mid + 1
        else:
            high = mid - 1
    return -1

def binary_search_recursive(arr, target, low, high):
    if low > high:
        return -1

    mid = (low + high) // 2

    if arr[mid] == target:
        return mid
    elif arr[mid] < target:
        return binary_search_recursive(arr, target, mid + 1, high)
    else:
        return binary_search_recursive(arr, target, low, mid - 1)

if __name__ == "__main__":
    my_list = [2, 3, 4, 10, 40]
    target_1 = 10
    target_2 = 50

    # Iterative version
    result_iterative_1 = binary_search_iterative(my_list, target_1)
    result_iterative_2 = binary_search_iterative(my_list, target_2)

    print(f"Iterative search for {target_1}: Index {result_iterative_1}")
    print(f"Iterative search for {target_2}: Index {result_iterative_2}")

    # Recursive version
    result_recursive_1 = binary_search_recursive(my_list, target_1, 0, len(my_list) - 1)
    result_recursive_2 = binary_search_recursive(my_list, target_2, 0, len(my_list) - 1)

    print(f"Recursive search for {target_1}: Index {result_recursive_1}")
    print(f"Recursive search for {target_2}: Index {result_recursive_2}")
